#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int ingredients[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &ingredients[i]);
        }
        uint64_t max_score = 0;
        for (uint64_t mask = 0; mask < (1ULL << N); mask++) {
            int score_A = 0, score_B = 0;
            for (int i = 0; i < N; i++) {
                if (mask & (1ULL << i)) {
                    score_A += ingredients[i];
                } else {
                    score_B += ingredients[i];
                }
            }
            max_score += (score_A > score_B) ? score_A - score_B : score_B - score_A;
        }
        printf("%llu\n", max_score % (10000000 + 10));
    }
    return 0;
}

