const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const ingredients = readline().split(' ').map(Number);
    let max_score = 0;
    for (let mask = 0; mask < (1 << N); mask++) {
        let score_A = 0, score_B = 0;
        for (let j = 0; j < N; j++) {
            if (mask & (1 << j)) {
                score_A += ingredients[j];
            } else {
                score_B += ingredients[j];
            }
        }
        max_score += Math.max(score_A - score_B, score_B - score_A);
    }
    console.log(max_score % (Math.pow(10, 7) + 10));
}
